document.addEventListener("DOMContentLoaded", () => {
  gsap.registerPlugin(ScrollTrigger);

  const lenis = new Lenis();
  lenis.on("scroll", ScrollTrigger.update);
  gsap.ticker.add((time) => {
    lenis.raf(time * 1000);
  });
  gsap.ticker.lagSmoothing(0);

  const stickySection = document.querySelector(".sticky");
  const slidesContainer = document.querySelector(".slides");
  const slider = document.querySelector(".slider");
  const slides = document.querySelectorAll(".slide");

  const stickyHeight = window.innerHeight * 6;
  const totalMove = slidesContainer.offsetWidth - slider.offsetWidth;
  const slideWidth = slider.offsetWidth;

  slides.forEach((slide) => {
    const title = slide.querySelector(".title h1");
    gsap.set(title, { y: -200 });
  });

  let currentVisibleIndex = null;

  const observer = new IntersectionObserver(
    (entries) => {
      entries.forEach((entry) => {
        const currentIndex = Array.from(slides).indexOf(entry.target);
        const titles = Array.from(slides).map((slide) =>
          slide.querySelector(".title h1")
        );

        if (entry.intersectionRatio >= 0.25) {
          currentVisibleIndex = currentIndex;
          titles.forEach((title, index) => {
            gsap.to(title, {
              y: index === currentIndex ? 0 : -200,
              duration: 0.5,
              ease: "power2.out",
              overwrite: true,
            });
          });
        } else if (
          entry.intersectionRatio < 0.25 &&
          currentVisibleIndex === currentIndex
        ) {
          const prevIndex = currentIndex - 1;
          currentVisibleIndex = prevIndex >= 0 ? prevIndex : null;

          titles.forEach((title, index) => {
            gsap.to(title, {
              y: index === prevIndex ? 0 : -200,
              duration: 0.5,
              ease: "power2.out",
              overwrite: true,
            });
          });
        }
      });
    },
    {
      root: slider,
      threshold: [0, 0.25],
    }
  );

  slides.forEach((slide) => observer.observe(slide));

  ScrollTrigger.create({
    trigger: stickySection,
    start: "top top",
    end: `+=${stickyHeight}px`,
    scrub: 1,
    pin: true,
    pinSpacing: true,
    onUpdate: (self) => {
      const progress = self.progress;
      const mainMove = progress * totalMove;

      gsap.set(slidesContainer, {
        x: -mainMove,
      });

      const currentSlide = Math.floor(mainMove / slideWidth);
      const slideProgress = (mainMove % slideWidth) / slideWidth;

      slides.forEach((slide, index) => {
        const image = slide.querySelector("img");
        if (image) {
          if (index === currentSlide || index === currentSlide + 1) {
            const relativeProgress =
              index === currentSlide ? slideProgress : slideProgress - 1;
            const parallaxAmount = relativeProgress * slideWidth * 0.25;
            gsap.set(image, {
              x: parallaxAmount,
              scale: 1.35,
            });
          } else {
            gsap.set(image, {
              x: 0,
              scale: 1.35,
            });
          }
        }
      });
    },
  });
});

code.styles.css:
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html,
body {
  width: 100%;
  height: 700vh;
  font-family: "Gilroy";
}

img {
  position: relative;
  width: 100%;
  height: 100%;
  object-fit: cover;
  will-change: transform, scale;
  transform: translateX(0) scale(1.35);
}

section {
  position: relative;
  width: 100vw;
  height: 100vh;
  padding: 1.5em;
  overflow: hidden;
}

section.outro {
  background-color: #141414;
  display: flex;
  justify-content: center;
  align-items: center;
  text-align: center;
}

.outro h1 {
  color: #fff;
  text-transform: uppercase;
  font-size: 60px;
  font-weight: 900;
  letter-spacing: -2px;
  line-height: 0.9;
}

section.sticky {
  background-color: #b4aea7;
}

.slider {
  position: relative;
  width: 100%;
  height: 100%;
  overflow: hidden;
}

.slides {
  position: relative;
  width: 500%;
  height: 100%;
  display: flex;
  will-change: transform;
  transform: translateX(0);
}

.slide {
  position: relative;
  flex: 1;
  height: 100%;
}

.img {
  position: absolute;
  width: 100%;
  height: 100%;
  overflow: hidden;
}

.title {
  position: relative;
  width: max-content;
  height: 200px;
  margin: 1.5em;
  clip-path: polygon(0 0, 100% 0, 100% 100%, 0% 100%);
  z-index: 2;
}

.title h1 {
  position: relative;
  color: #fff;
  text-transform: uppercase;
  font-size: 85px;
  font-weight: 900;
  letter-spacing: -2px;
  line-height: 0.9;
  will-change: transform;
}

.lenis.lenis-smooth [data-lenis-prevent] {
  overscroll-behavior: contain;
}

.lenis.lenis-stopped {
  overflow: clip;
}

.lenis.lenis-smooth iframe {
  pointer-events: none;
}
